sequence.script:
// Get payload as JSON
var payload = mc.getPayloadJSON();

// Get claimId from property (vars.claimId equivalent)
var claimId = mc.getProperty("claimId");

// Function to format date as yyyyMMddHHSSS
function getFormattedTimestamp() {
    var now = new Date();

    function pad(n, width) {
        n = n + '';
        return n.length >= width ? n : new Array(width - n.length + 1).join('0') + n;
    }

    var year = now.getFullYear();
    var month = pad(now.getMonth() + 1, 2);
    var day = pad(now.getDate(), 2);
    var hours = pad(now.getHours(), 2);

    // NOTE: DataWeave uses SSS = milliseconds
    var millis = pad(now.getMilliseconds(), 3);

    return year + month + day + hours + millis;
}

// Generate timestamp
var ts = getFormattedTimestamp();

// Construct new fields
var result = {};
result.claimId = claimId;
result.fraudCheckId = "FRDC-" + ts;

// Merge payload into result
for (var key in payload) {
    if (payload.hasOwnProperty(key)) {
        result[key] = payload[key];
    }
}

// Set final payload
mc.setPayloadJSON(result);
